import java.util.Scanner;

public class BufferOverflowFixed {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.next();

        // Use Math.min to prevent buffer overflow
        char[] buffer = new char[10];
        String safeName = name.substring(0, Math.min(name.length(), buffer.length));
        safeName.getChars(0, safeName.length(), buffer, 0);

        System.out.println("Welcome, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
